const validateForm = (data, requiredFields) => {
  const missingFields = requiredFields.filter((field) => {
    const value = data[field.name];
    if (Array.isArray(value)) return value.length === 0;
    if (typeof value === "string") return value.trim() === "";
    return !value;
  });
  return missingFields;
};

const createDraftStockAdjustment = async (
  entry,
  organizationId,
  stockCountId,
) => {
  try {
    // Filter items with variance (variance_qty !== 0)
    const itemsWithVariance = entry.table_stock_count.filter(
      (item) => item.variance_qty !== 0 && item.line_status === "Approved",
    );

    if (itemsWithVariance.length === 0) {
      console.log("No items with variance - no stock adjustment needed");
      return null;
    }

    // Group items by material_id
    const groupedByMaterial = {};

    for (const item of itemsWithVariance) {
      if (!groupedByMaterial[item.material_id]) {
        groupedByMaterial[item.material_id] = [];
      }
      groupedByMaterial[item.material_id].push(item);
    }

    // Create stock adjustment table entries
    const stockAdjustmentTable = [];

    for (const materialId in groupedByMaterial) {
      const items = groupedByMaterial[materialId];
      const firstItem = items[0];

      // Fetch item balance data for each item
      const balanceIndex = [];
      let totalQuantity = 0;
      const adjSummaryDetails = [];

      for (const item of items) {
        // Use adjusted_qty if different from variance_qty, otherwise use variance_qty
        let varianceToUse = item.variance_qty;
        if (
          item.adjusted_qty !== undefined &&
          item.adjusted_qty !== null &&
          item.adjusted_qty !== item.variance_qty
        ) {
          varianceToUse = item.adjusted_qty;
          console.log(
            `Using adjusted_qty (${item.adjusted_qty}) instead of variance_qty (${item.variance_qty}) for item ${item.material_id}`,
          );
        }

        // Convert variance to base UOM if needed
        let varianceQtyInBaseUOM = varianceToUse;

        if (item.uom_id !== item.base_uom_id) {
          console.log(
            `Converting variance_qty from ${item.uom_id} to base UOM ${item.base_uom_id}`,
          );

          // Check if table_uom_conversion is already stored (from UOM change)
          let tableUOMConversion = item.table_uom_conversion;

          // If not available, fetch from Item collection
          if (!tableUOMConversion) {
            console.log(
              `table_uom_conversion not found in item data, fetching from database for item ${item.material_id}`,
            );
            const itemData = await db
              .collection("Item")
              .where({ id: item.material_id })
              .get();

            if (itemData.data && itemData.data.length > 0) {
              tableUOMConversion = itemData.data[0].table_uom_conversion;
              console.log("Fetched table_uom_conversion from database");
            } else {
              console.warn(
                `Could not fetch item data for ${item.material_id}, using original value`,
              );
            }
          }

          // Handle different data formats
          if (typeof tableUOMConversion === "string") {
            try {
              tableUOMConversion = JSON.parse(tableUOMConversion);
              console.log("✅ Parsed table_uom_conversion from JSON string");
              console.log("Parsed array length:", tableUOMConversion?.length);
            } catch (e) {
              console.warn(
                "❌ Failed to parse table_uom_conversion as JSON:",
                e,
              );
              tableUOMConversion = null;
            }
          }

          // If it's a single object (not array), wrap it in an array
          if (tableUOMConversion && !Array.isArray(tableUOMConversion)) {
            console.log("Converting single object to array");
            tableUOMConversion = [tableUOMConversion];
          }

          if (tableUOMConversion && Array.isArray(tableUOMConversion)) {
            console.log(
              `Searching for conversion: alt_uom_id === ${item.uom_id}`,
            );

            // Find the conversion for current UOM
            const currentUOMConversion = tableUOMConversion.find(
              (conv) => conv.alt_uom_id === item.uom_id,
            );

            console.log("Found conversion:", currentUOMConversion);

            if (currentUOMConversion && currentUOMConversion.base_qty) {
              // Convert from alt UOM back to base UOM
              varianceQtyInBaseUOM =
                varianceToUse * currentUOMConversion.base_qty;
              console.log(
                `✅ Converted variance: ${varianceToUse} × ${currentUOMConversion.base_qty} = ${varianceQtyInBaseUOM}`,
              );
            } else {
              console.warn(
                `⚠️ No conversion found for UOM ${item.uom_id}, using original value`,
              );
              console.log(
                "Available conversions:",
                tableUOMConversion.map((c) => c.alt_uom_id),
              );
            }
          } else {
            console.warn(
              `⚠️ No valid table_uom_conversion data available, using original value`,
            );
          }
        }

        // Fetch the item balance record
        // Use item_batch_balance for batched items, item_balance for non-batched
        const collectionName = item.batch_id
          ? "item_batch_balance"
          : "item_balance";

        const itemBalanceQuery = db.collection(collectionName).where({
          material_id: item.material_id,
          plant_id: item.plant_id,
          location_id: item.location_id,
          is_deleted: 0,
        });

        // Add batch filter for batched items
        if (item.batch_id) {
          itemBalanceQuery.where({ batch_id: item.batch_id });
        }

        const itemBalanceResult = await itemBalanceQuery.get();

        if (itemBalanceResult.data && itemBalanceResult.data.length > 0) {
          const balanceData = itemBalanceResult.data[0];

          // Determine movement type based on variance (using base UOM quantity)
          const movementType = varianceQtyInBaseUOM > 0 ? "In" : "Out";
          const saQuantity = Math.abs(varianceQtyInBaseUOM);

          totalQuantity += saQuantity;

          // Create balance index entry
          const balanceIndexEntry = {
            balance_id: balanceData.id,
            material_id: balanceData.material_id,
            plant_id: balanceData.plant_id,
            location_id: balanceData.location_id,
            batch_id: balanceData.batch_id || null,
            balance_quantity: balanceData.balance_quantity,
            unrestricted_qty: balanceData.unrestricted_qty,
            block_qty: balanceData.block_qty,
            qualityinsp_qty: balanceData.qualityinsp_qty,
            reserved_qty: balanceData.reserved_qty,
            intransit_qty: balanceData.intransit_qty,
            organization_id: balanceData.organization_id,
            tenant_id: balanceData.tenant_id,
            create_user: balanceData.create_user,
            create_time: balanceData.create_time,
            create_dept: balanceData.create_dept,
            update_user: balanceData.update_user,
            update_time: balanceData.update_time,
            is_deleted: balanceData.is_deleted,
            category: "Unrestricted",
            movement_type: movementType,
            sa_quantity: saQuantity,
          };

          balanceIndex.push(balanceIndexEntry);

          // Get location name
          const locationResult = await db
            .collection("bin_location")
            .where({ id: item.location_id })
            .get();
          const locationName =
            locationResult.data?.[0]?.bin_location_combine || item.location_id;

          // Get base UOM name (Stock Adjustment uses base UOM)
          const uomResult = await db
            .collection("unit_of_measurement")
            .where({ id: item.base_uom_id })
            .get();
          const uomName = uomResult.data?.[0]?.uom_name || "";

          // Get batch name if exists
          let batchName = "";
          if (item.batch_id) {
            const batchResult = await db
              .collection("batch")
              .where({ id: item.batch_id })
              .get();
            batchName = batchResult.data?.[0]?.batch_number || "";
          }

          // Build adjustment summary detail
          const categoryAbbr = "UNR"; // Unrestricted
          const movementTypeLabel = movementType === "In" ? "IN" : "OUT";
          let detailLine = `${locationName}: ${saQuantity} ${uomName} (${categoryAbbr}) - ${movementTypeLabel}`;
          if (batchName) {
            detailLine += `\n[${batchName}]`;
          }
          adjSummaryDetails.push(detailLine);
        }
      }

      // Get base UOM name for summary (Stock Adjustment always uses base UOM)
      const baseUomResult = await db
        .collection("unit_of_measurement")
        .where({ id: firstItem.base_uom_id })
        .get();
      const baseUomName = baseUomResult.data?.[0]?.uom_name || "";

      // Build adjustment summary
      const adjSummary = `Total: ${totalQuantity} ${baseUomName}\nDETAILS:\n${adjSummaryDetails
        .map((detail, idx) => `${idx + 1}. ${detail}`)
        .join("\n")}`;

      // Get material name
      const materialResult = await db
        .collection("Item")
        .where({ id: materialId })
        .get();
      const materialName = materialResult.data?.[0]?.material_name || "";

      // Create stock adjustment entry (always use base UOM)
      stockAdjustmentTable.push({
        material_id: materialId,
        uom_id: firstItem.base_uom_id,
        material_name: materialName,
        item_category: firstItem.item_category,
        is_serialized_item: firstItem.is_serialized || 0,
        is_single_serial: firstItem.is_single || 0,
        total_quantity: totalQuantity,
        balance_index: JSON.stringify(balanceIndex),
        adj_summary: adjSummary,
      });
    }

    // Generate draft prefix
    const saPrefixID = await db
      .collection("su_code_serial_no_rule")
      .where({
        department_id: organizationId,
        business_type: "Stock Adjustment",
        is_default: 1,
      })
      .get();

    // Create stock adjustment document
    const stockAdjustmentDoc = {
      stock_adjustment_status: "Draft",
      organization_id: organizationId,
      adjustment_no: "draft",
      adjustment_no_type: saPrefixID?.data[0]?.id || null,
      stock_count_id: stockCountId,
      adjustment_date: new Date().toISOString().split("T")[0],
      adjustment_type: "Stock Count",
      adjusted_by: this.getVarGlobal("nickname"),
      plant_id: entry.plant_id,
      adjustment_remarks: entry.stock_count_remark || "",
      adjustment_remarks2: entry.stock_count_remark2 || "",
      adjustment_remarks3: entry.stock_count_remark3 || "",
      stock_adjustment: stockAdjustmentTable,
    };

    // Save to database
    const stockAdjustmentResult = await db
      .collection("stock_adjustment")
      .add(stockAdjustmentDoc);

    console.log("Stock Adjustment Created:", stockAdjustmentDoc);
    this.$message.success(
      `Draft Stock Adjustment created: ${stockAdjustmentResult.data[0].adjustment_no} with ${stockAdjustmentTable.length} item(s)`,
    );

    return stockAdjustmentResult.data[0];
  } catch (error) {
    console.error("Error creating stock adjustment:", error);
    this.$message.error("Failed to create stock adjustment");
  }
};

